msg.topic = "Generación";
msg.payload = Math.floor(Math.random() * 1000) + 200;

flow.set("generacion", msg.payload);

return msg;

// ============================================
// FUNCIÓN PARA GRÁFICA DE CONSUMO
// Recibe datos desde "suma de circuitos"
// ============================================

// El valor de consumo real viene en msg.payload
let consumoReal = msg.payload;

// Asegurar que sea número
consumoReal = Number(consumoReal);
if (isNaN(consumoReal)) consumoReal = 0;

// Configurar mensaje para la gráfica
msg.topic = "Consumo";
msg.payload = consumoReal;

// Guardar para otros nodos (compatibilidad)
flow.set("consumo", consumoReal);

// Depuración
node.warn(`📊 GRÁFICA CONSUMO REAL: ${consumoReal} W`);

return msg;

let gen = flow.get("generacion");
let con = flow.get("consumo");

if (gen === undefined || con === undefined) {
    return null;
}

let estado = gen > con;
let mensaje = estado ? "ENERGÍA SUFICIENTE" : "CONSUMO EXCESIVO";
let color = estado ? "#00ff00" : "#ff4444";
let fondo = estado ? "#0a2e0a" : "#2a0000";
let emoji = estado ? "✅⚡" : "⚠️🔥";

msg.payload = `
<div style="
    background: ${fondo};
    border-radius: 20px;
    padding: 20px;
    text-align: center;
    border: 2px solid ${color};
    box-shadow: 0 0 20px ${color};
">
    <div style="font-size: 48px;">${emoji}</div>
    <div style="font-size: 22px; font-weight: bold; color: ${color}; margin: 10px 0;">
        ${mensaje}
    </div>
    <div style="font-size: 32px; font-weight: bold;">
        <span style="color: #00ff00;">${gen}</span>
        <span style="color: white;"> vs </span>
        <span style="color: #ff9800;">${con}</span>
    </div>
    <div style="font-size: 18px; margin-top: 10px; color: ${color};">
        ${estado ? `✔ +${gen - con} W` : `⚠ -${con - gen} W`}
    </div>
</div>
`;

return msg;

// Obtener energía del MPPT (no del WiFi)
let energiaMPPT = flow.get("energia_mppt") || 500;

// Obtener factor WiFi
let factorWiFi = flow.get("factor_wifi") || 1;

// Aplicar factor WiFi a la energía
let energiaDC = energiaMPPT * factorWiFi;

let eficiencia = 0.9;
let salida = energiaDC * eficiencia;

msg.payload = Math.round(salida);

node.warn(`Inversor: ${energiaMPPT}W (MPPT) × ${factorWiFi} (WiFi) × 0.9 = ${msg.payload}W`);

// Guardar para otros nodos
flow.set("energia_ac", msg.payload);

return msg;

let gen = flow.get("generacion") || 0;
let con = flow.get("consumo") || 0;

if (gen === 0 || con === 0) {
    return null;
}

// nueva fórmula coherente
let eficiencia = (gen / con) * 100;

// limitar a 100% máximo
if (eficiencia > 100) {
    eficiencia = 100;
}

msg.payload = eficiencia.toFixed(2) + " %";

return msg;

let consumo = msg.payload;

if (consumo > 900) {
    msg.payload = "🔴 Sobreconsumo";
} else if (consumo > 600) {
    msg.payload = "🟡 Consumo medio";
} else {
    msg.payload = "🟢 Consumo normal";
}

return msg;

let entrada = msg.payload;
let salida = entrada * 0.98;

msg.payload = salida;

flow.set("entrada_mcu", entrada);
flow.set("salida_mcu", salida);

return msg;

let entrada = flow.get("entrada_mcu");
let salida = flow.get("salida_mcu");

if (entrada === undefined || salida === undefined) {
    return null;
}

msg.payload = "Entrada: " + entrada.toFixed(2) +
    " W → Salida: " + salida.toFixed(2) + " W";

return msg;

// ============================================
// RADIACIÓN SOLAR (TEMPERATURA LIGADA)
// ============================================

// 1. Generar radiación
let radiacion = Math.floor(Math.random() * 1200);

// 2. Calcular temperatura y porcentajes SEGÚN radiación
let temperatura;
let climaTexto;
let pClima, pVentila, pEquipos, pIlumina;

if (radiacion <= 200) {
    temperatura = 20;
    climaTexto = "🌧️ Nublado";
    pClima = 0.00;
    pVentila = 0.00;
    pEquipos = 0.40;
    pIlumina = 0.60;
}
else if (radiacion <= 400) {
    temperatura = 23;
    climaTexto = "🌥️ Parcial nublado";
    pClima = 0.00;
    pVentila = 0.15;
    pEquipos = 0.35;
    pIlumina = 0.50;
}
else if (radiacion <= 600) {
    temperatura = 25;
    climaTexto = "🌤️ Soleado suave";
    pClima = 0.00;
    pVentila = 0.30;
    pEquipos = 0.35;
    pIlumina = 0.35;
}
else if (radiacion <= 800) {
    temperatura = 27;
    climaTexto = "☀️ Soleado moderado";
    pClima = 0.15;
    pVentila = 0.30;
    pEquipos = 0.30;
    pIlumina = 0.25;
}
else if (radiacion <= 1000) {
    temperatura = 29;
    climaTexto = "🔆 Soleado fuerte";
    pClima = 0.35;
    pVentila = 0.20;
    pEquipos = 0.25;
    pIlumina = 0.20;
}
else {
    temperatura = 32;
    climaTexto = "🔥 Muy caluroso";
    pClima = 0.50;
    pVentila = 0.15;
    pEquipos = 0.20;
    pIlumina = 0.15;
}

// 3. Guardar variables
flow.set("radiacion_solar", radiacion);
flow.set("temperatura", temperatura);
flow.set("clima_texto", climaTexto);
flow.set("p_clima", pClima);
flow.set("p_ventila", pVentila);
flow.set("p_equipos", pEquipos);
flow.set("p_ilumina", pIlumina);

// ============================================
// 4. ENVIAR A MÚLTIPLES SALIDAS
// ============================================

// Salida 1: MPPT (recibe radiación)
let msgMPPT = { payload: radiacion };

// Salida 2: Control Clima (recibe radiación)
let msgControl = { payload: radiacion };

// 5. Depuración
node.warn(`☀️ ${radiacion}W/m² → 🌡️ ${temperatura}°C | ${climaTexto}`);
node.warn(`📊 Aire:${pClima * 100}% | Vent:${pVentila * 100}% | Equip:${pEquipos * 100}% | Luz:${pIlumina * 100}%`);

// Enviar a 2 salidas
return [[msgMPPT], [msgControl]];

// Esta función va ANTES del gauge
let bateria_wh = flow.get("bateria_wh") || 15000;

// Enviar SOLO el número (sin texto, sin porcentaje)
msg.payload = Math.round(bateria_wh);

return msg;

// Energía que llega del inversor
let energiaAC = msg.payload || 0;

// Leer porcentajes desde Control Clima
let pClima = flow.get("p_clima") || 0.40;
let pVentila = flow.get("p_ventila") || 0.15;
let pEquipos = flow.get("p_equipos") || 0.25;
let pIlumina = flow.get("p_ilumina") || 0.20;

// Calcular consumos
let clima = Math.round(energiaAC * pClima);
let equipos = Math.round(energiaAC * pEquipos);
let iluminacion = Math.round(energiaAC * pIlumina);
let ventilacion = Math.round(energiaAC * pVentila);

// Enviar a los 4 circuitos
return [
    { payload: clima },
    { payload: equipos },
    { payload: iluminacion },
    { payload: ventilacion }
];

msg.payload = msg.payload;
flow.set("climatizacion", msg.payload);
return msg;

msg.payload = msg.payload;
flow.set("equipos", msg.payload);
return msg;

msg.payload = msg.payload;
flow.set("iluminacion", msg.payload);
return msg;

let valor = msg.payload;
if (typeof valor === 'object' && valor !== null) {
    valor = valor.payload || valor;
}
valor = Number(valor);
if (isNaN(valor)) valor = 0;
msg.payload = Math.round(valor);
flow.set("ventilacion", msg.payload);
return msg;
